// Go app sends a JSON body — not multipart.
// Extract fields from body (n8n puts webhook JSON under item.json.body OR item.json directly).
const item = $input.first();
const raw = item.json;
const body = (raw && typeof raw.body === 'object' && raw.body !== null) ? raw.body : raw;

const requiredFields = ['tenant_id', 'job_position_id', 'queue_file_id', 'attachment_base64'];
for (const f of requiredFields) {
  if (!body[f]) throw new Error(`Missing required field: ${f}`);
}

const filename = (body.attachment_filename || 'resume.pdf')
  .replace(/[^a-zA-Z0-9._\- ]/g, '_');
const contentType = body.attachment_content_type || 'application/pdf';

// Decode base64 → binary
const binaryBuffer = Buffer.from(body.attachment_base64, 'base64');
const binaryData = await this.helpers.prepareBinaryData(binaryBuffer, filename, contentType);

return [{
  json: {
    tenant_id:        body.tenant_id,
    job_position_id:  body.job_position_id,
    queue_id:         body.queue_id         || '',
    queue_file_id:    body.queue_file_id,
    attachment_filename:     filename,
    attachment_content_type: contentType,
    resume_plain_text: body.resume_plain_text || '',
    resume_text_hash:  body.resume_text_hash  || '',
    storage_path:      body.storage_path      || '',
    app_base_url:      body.app_base_url      || ''
  },
  binary: { data: binaryData }
}];

// Merge Drive upload result with original webhook fields.
const driveResult = $input.first().json;
const ctx = $('Prepare Resume Binary3').item.json;

const driveFileId = driveResult.id || driveResult.fileId || '';
const driveUrl = driveFileId
  ? `https://drive.google.com/file/d/${driveFileId}/view`
  : '';

return [{
  json: {
    ...ctx,
    drive_file_id: driveFileId,
    resume_url:    driveUrl || ctx.storage_path
  }
}];

function esc(v) {
  return (v == null ? '' : String(v).replace(/'/g, "''").trim());
}

const candidate = $('Upsert Candidate3').item.json;
const ctx = $('Extract AI Fields').item.json;

let posProfileId = '';
try {
  posProfileId = $('Upsert Position Profile3').item.json.position_profile_id || '';
} catch (e) {
  posProfileId = '';
}

return [{
  json: {
    q_status: 'completed',
    q_parsed_name:  esc(candidate.candidate_name || ctx.parsed_full_name),
    q_parsed_email: esc(candidate.candidate_email || ctx.parsed_email),
    q_parsed_phone: esc(candidate.candidate_phone || ctx.parsed_phone),
    q_candidate_id: candidate.candidate_id,
    q_pos_profile_id: posProfileId,
    q_queue_file_id: ctx.queue_file_id
  }
}];

const upd = $('Prepare Queue Update Data3').item.json;

return [{
  json: {
    ok:                  true,
    candidate_id:        upd.q_candidate_id,
    position_profile_id: upd.q_pos_profile_id,
    parsed_name:         upd.q_parsed_name,
    parsed_email:        upd.q_parsed_email,
    parsed_phone:        upd.q_parsed_phone,
    queue_file_id:       upd.q_queue_file_id
  }
}];

const row = $input.first()?.json || {};
const ctx = $('Prepare Resume Binary3').item.json || {};
const folderId = String(row.drive_upload_folder_id || '').trim();
if (row.drive_status === false) {
  throw new Error('Tenant Drive folders not provisioned. Run Create Tenant Drive Folders workflow or set drive_status=true on tenants.');
}
if (!folderId) {
  throw new Error('Missing drive_upload_folder_id for tenant ' + (row.tenant_id || ctx.tenant_id || '?') + ' job ' + (ctx.job_position_id || '?') + '. Check drive_naukri_folder_id.');
}
const binary = { ...($('Prepare Resume Binary3').first()?.binary || {}) };
if (!binary.data) {
  const keys = Object.keys(binary).join(', ') || '(none)';
  throw new Error('Validate Drive folder: no resume binary on Prepare Resume Binary. Keys: ' + keys);
}
return [{
  json: {
    ...ctx,
    tenant_id: row.tenant_id || ctx.tenant_id,
    job_position_id: ctx.job_position_id,
    drive_upload_folder_id: folderId,
    drive_naukri_folder_id: row.drive_naukri_folder_id,
    ingest_source: row.ingest_source || 'naukri_bulk',
  },
  binary,
}];

const aiResp = $input.first().json;
const ctx = $('Build Drive Context3').item.json;

function esc(v) {
  return (v == null ? '' : String(v).replace(/'/g, "''").trim());
}

let p = {};
try {
  const block = aiResp?.output?.[0]?.content?.[0];
  const t = block?.text;
  if (t != null && typeof t === 'object') {
    p = t;
  } else if (typeof t === 'string' && t.trim() !== '') {
    p = JSON.parse(t);
  }

  if (!p || Object.keys(p).length === 0) {
    const raw =
      aiResp?.message?.content ||
      aiResp?.choices?.[0]?.message?.content ||
      '';
    if (typeof raw === 'string' && raw.trim() !== '') {
      p = JSON.parse(raw);
    }
  }
} catch (e) {
  p = {};
}

function escTrunc(v, max) {
  const s = (v == null ? '' : String(v).replace(/'/g, "''").trim());
  return s.substring(0, max);
}

const fullName = escTrunc(p.full_name || p.name || ctx.attachment_filename || '', 255);
const email = escTrunc((p.email || '').toLowerCase(), 255);
const phone = escTrunc(p.phone || '', 50);

return [{
  json: {
    tenant_id: ctx.tenant_id,
    job_position_id: ctx.job_position_id,
    queue_id: ctx.queue_id,
    queue_file_id: ctx.queue_file_id,
    drive_file_id: ctx.drive_file_id,
    resume_url: escTrunc(ctx.resume_url, 500),
    create_position_profile: ctx.create_position_profile !== false,

    sq_full_name: fullName || 'Unknown Candidate',
    sq_email: email,
    sq_phone: phone,
    sq_current_role:     escTrunc(p.current_role || '', 255),
    sq_current_company:  escTrunc(p.current_company || '', 255),
    sq_previous_company: escTrunc(p.previous_company || '', 255),
    sq_total_experience: escTrunc(p.total_experience || '', 255),
    sq_skills:           escTrunc(p.skills || '', 255),
    sq_education:        escTrunc(p.education || '', 255),
    sq_current_location: escTrunc(p.current_location || '', 255),
    sq_current_ctc:      escTrunc(p.current_ctc || '', 255),
    sq_expected_ctc:     escTrunc(p.expected_ctc || '', 255),
    sq_notice_period:    escTrunc(p.notice_period || '', 255),
    sq_linkedin_url:     escTrunc(p.linkedin_url || '', 255),
    sq_resume_url:       escTrunc(ctx.resume_url || ctx.storage_path, 255),

    parsed_full_name: fullName,
    parsed_email: email,
    parsed_phone: phone
  }
}];
